// ROLLUP_NO_REPLACE 
 const _20251031AffinityEstGratuit = "{\"parsed\":{\"_path\":\"/fr/20251031-affinity-est-gratuit\",\"_dir\":\"fr\",\"_draft\":false,\"_partial\":false,\"_locale\":\"\",\"title\":\"Affinity passe au gratuit, et Internet s'énerve déjà\",\"description\":\"Affinity devient gratuit et bouleverse le marché de la création graphique. Découvrez pourquoi cette évolution est une excellente nouvelle pour concurrencer Adobe, avec une suite unifiée performante et sans abonnement.\",\"image\":\"/images/articles/affinity.jpg\",\"createdAt\":\"2025-10-31\",\"id\":\"2025-10-31T00:00:00.000Z\",\"keywords\":\"Affinity, critique Adobe, Affinity Designer, abonnement Adobe, frais cachés Adobe, service client Adobe, alternatives Adobe, pratiques commerciales Adobe, procès Adobe, FTC Adobe\",\"summary\":\"Affinity passe au modèle gratuit avec une suite unifiée réunissant Vector, Layout et Photo dans une seule application. Une alternative performante à Adobe sans abonnement obligatoire, accessible à tous les créatifs.\",\"body\":{\"type\":\"root\",\"children\":[{\"type\":\"element\",\"tag\":\"h1\",\"props\":{\"id\":\"affinity-passe-au-gratuit-et-internet-sénerve-déjà\"},\"children\":[{\"type\":\"text\",\"value\":\"Affinity passe au gratuit, et Internet s'énerve déjà\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Affinity vient, une fois de plus, de bouleverser la donne. Jusqu'à présent, la suite créative était payante — un achat unique pour chaque version majeure , sans abonnement, ce qui en faisait une alternative sérieuse à Adobe.\\nMais depuis peu, Affinity est devenue gratuite. Oui, gratuite.\\nÀ une petite condition : il faut désormais un compte Canva pour accéder aux fonctionnalités liées à l'intelligence artificielle, comme la génération d'images.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Et franchement, c'est une excellente nouvelle.\"}]},{\"type\":\"element\",\"tag\":\"h2\",\"props\":{\"id\":\"pourquoi-cest-une-bonne-chose\"},\"children\":[{\"type\":\"text\",\"value\":\"Pourquoi c'est une bonne chose\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Je fais partie de ceux qui ont acheté la version 1, puis la version 2. Et pourtant, je me réjouis de cette évolution.\\nParce qu'un monde où Adobe ne règne pas seul sur la création graphique est, selon moi, un monde meilleur.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Soyons justes : Adobe reste une référence. Je n'ai toujours pas trouvé d'équivalent à Lightroom, notamment pour retoucher mes photos prises avec ma Ricoh Theta. Même Darktable ou Affinity Photo n'arrivent pas tout à fait à ce niveau.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Mais pour tout le reste, Affinity reste mon choix préféré à cause de son interface claire, plus cohérente que celle d'Adobe, et de son modèle économique sans abonnement. Ajoutez à cela une excellente performance et une expérience unifiée sur toutes les plateformes (sauf Linux, malheureusement, où il n'existe pas encore de version native).\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Le fait que cette suite devienne accessible à tous, sans barrière financière, est une excellente nouvelle pour les créatifs indépendants.\"}]},{\"type\":\"element\",\"tag\":\"h2\",\"props\":{\"id\":\"oui-mais-jai-payé-moi\"},\"children\":[{\"type\":\"text\",\"value\":\"\\\"Oui mais j'ai payé, moi\\\"\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Il fallait bien que ça arrive.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Forcément, tout le monde n'est pas du même avis.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"D'un côté, certains utilisateurs estiment qu'ils devraient conserver un accès exclusif puisqu'ils ont acheté leur licence. De l'autre, certains craignent que l'intégration payante des fonctionnalités IA de Canva soit le début d'une transition vers un modèle par abonnement.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Et je comprends ces inquiétudes.\\nMais après avoir testé cette nouvelle version — appelons-la Affinity 3.0 — je peux le dire : c'est une belle évolution.\"}]},{\"type\":\"element\",\"tag\":\"h2\",\"props\":{\"id\":\"une-suite-unifiée-fluide-et-bien-pensée\"},\"children\":[{\"type\":\"text\",\"value\":\"Une suite unifiée, fluide et bien pensée\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"La grande nouveauté, c'est qu'il n'est plus nécessaire de jongler entre trois logiciels.\\nTout est désormais réuni dans une seule application.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Trois espaces de travail :\"}]},{\"type\":\"element\",\"tag\":\"ul\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"\\\"Vecteur\\\" pour le dessin vectoriel,\"}]},{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"\\\"Mise en page\\\" pour la mise en page,\"}]},{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"\\\"Pixel\\\" pour la retouche d'image.\"}]}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"C'est une expérience unifiée, fluide et très agréable — même sur mes anciens MacBook Pro.\\nLes raccourcis restent identiques, les exports sont plus simples et plus rapides, et l'interface a gagné en cohérence.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"En quelques minutes, j'avais retrouvé mes repères.\\nPas de réapprentissage, pas de frustration. Juste la sensation familière de travailler dans un environnement stable et efficace.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Pour dire vrai,  à ceux qui s'indignent parce qu'ils ont payé avant les autres, je n'ai pas grand-chose à répondre. C'est un peu comme les fans de Maître Gims qui affirment être les \\\"vrais\\\" parce qu'ils l'écoutaient découper les instrumentaux à l'époque de Sexion d'Assaut, et refusent de reconnaître son évolution artistique.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"(Gims reste, quoi qu'on en dise, un excellent chanteur lyrique. )\"}]},{\"type\":\"element\",\"tag\":\"h2\",\"props\":{\"id\":\"en-résumé\"},\"children\":[{\"type\":\"text\",\"value\":\"En résumé\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Affinity 3.0 est une excellente surprise.\\nUne suite créative complète, moderne, performante et désormais accessible à tous.\\nLes outils d'IA sont optionnels, l'expérience reste soignée, et la philosophie \\\"anti-abonnement\\\" d'origine n'est pas trahie.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Alors au lieu de s'en offusquer, autant en profiter.\\nTéléchargez-la, testez-la, et surtout, créez.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Pour en savoir plus ou télécharger la suite, rendez-vous sur le site officiel :\\n\"},{\"type\":\"element\",\"tag\":\"a\",\"props\":{\"href\":\"https://affinity.serif.com/fr/\",\"rel\":[\"nofollow\"]},\"children\":[{\"type\":\"text\",\"value\":\"Affinity\"}]},{\"type\":\"text\",\"value\":\".\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Jean Luc Houédanou\"}]}],\"toc\":{\"title\":\"\",\"searchDepth\":2,\"depth\":2,\"links\":[{\"id\":\"pourquoi-cest-une-bonne-chose\",\"depth\":2,\"text\":\"Pourquoi c'est une bonne chose\"},{\"id\":\"oui-mais-jai-payé-moi\",\"depth\":2,\"text\":\"\\\"Oui mais j'ai payé, moi\\\"\"},{\"id\":\"une-suite-unifiée-fluide-et-bien-pensée\",\"depth\":2,\"text\":\"Une suite unifiée, fluide et bien pensée\"},{\"id\":\"en-résumé\",\"depth\":2,\"text\":\"En résumé\"}]}},\"_type\":\"markdown\",\"_id\":\"content:fr:20251031-affinity-est-gratuit.md\",\"_source\":\"content\",\"_file\":\"fr/20251031-affinity-est-gratuit.md\",\"_stem\":\"fr/20251031-affinity-est-gratuit\",\"_extension\":\"md\",\"sitemap\":{\"loc\":\"/fr/20251031-affinity-est-gratuit\"}},\"hash\":\"fq8Alhj8TH\"}";

export { _20251031AffinityEstGratuit as default };
